}

/*mobile view*/
.aa-DetachedContainer:not(.aa-DetachedContainer--modal) .item-image {
  display: none;
}

.item-image>img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  object-position: center;
}

.header-container {
  display: flex;
  flex-direction: column;
  justify-content: start;
  align-items: start;
  max-width: 100%;
  overflow: hidden;
}

.item-title-container {
  display: flex;
  flex-direction: row;
  justify-content: start;
  align-items: center;
  column-gap: 8px;
  max-width: 100%;
  border-bottom: 2px;
}

.item-url {
    margin: 0;
    font-size: 14px;
    line-height: normal;
    font-weight: lighter;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
    max-width: 100%;
}

.item-url:hover {
  color: #df2673;
}

.item-title {
  margin: 0;
  font-size: 19px;
  color: #5C5C61;
  font-weight: bold;

  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;

  /*For inline text*/
  /*flex-grow: 1;*/
  flex-shrink: 1;
}

.item-title:hover {
  color: #df2673;
}

.item-description {
  margin: 0;
  font-size: 14px;
  color: #5C5C61;
  line-height: normal !important;

  font-weight: lighter;

  line-height: 24px !important;
  max-height: 48px;

  overflow: hidden;
  display: -webkit-box;
  -webkit-box-orient: vertical;
  -webkit-line-clamp: 2;
  -webkit-box-pack: end;
}

.item-tag {
  margin: 0;
  font-size: 13px;
  justify-self: end;
  line-height: normal !important;
  text-align: center;
  padding-top: 1px;

  /*height: 26px; For right aligned*/
  /*width: 70px; For right aligned*/
  padding: 2px 6px;
  /* for next to title*/
  border-radius: 3px;
  background-color: #DF2673;
  color: white;
  display: flex;
  justify-content: center;
  align-items: center;
}

.aa-Form {
    outline: none !important;
    box-shadow: none !important;
}

.aa-Item[aria-selected="true"] {
  background-color: none !important;
  background: none !important;
}







